from functools import partial, lru_cache, singledispatch

# partial: freeze arguments
def power(base, exp):
    return base ** exp

square = partial(power, exp=2)
cube = partial(power, exp=3)
print(square(5))  # 25
print(cube(5))    # 125

# lru_cache: memoization
@lru_cache(maxsize=128)
def expensive_compute(n):
    return sum(range(n)) * 2  # pretend expensive

@lru_cache(maxsize=None)
def fib(n):
    if n < 2:
        return n
    return fib(n-1) + fib(n-2)

print(fib(100))  # 354224848179261915075 — instant
print(fib.cache_info())  # CacheInfo(hits=98, misses=101, ...)

# singledispatch: type-based dispatch
@singledispatch
def serialize(obj):
    raise TypeError(f'no serializer for {type(obj)}')

@serialize.register(int)
def _(obj):
    return str(obj)

@serialize.register(list)
def _(obj):
    return '[' + ', '.join(serialize(x) for x in obj) + ']'

@serialize.register(dict)
def _(obj):
    items = ', '.join(f'{k}: {serialize(v)}' for k, v in obj.items())
    return '{' + items + '}'

print(serialize({'a': [1, 2], 'b': 3}))
# {a: [1, 2], b: 3}

# Generator pipeline — no intermediate lists
import re

def read_lines(filename):
    with open(filename) as f:
        yield from f  # one line at a time

def filter_pattern(lines, pattern):
    regex = re.compile(pattern)
    for line in lines:
        if regex.search(line):
            yield line

def parse_fields(lines):
    for line in lines:
        parts = line.strip().split(',')
        yield {'timestamp': parts[0], 'status': parts[1]}

def compute_stats(records):
    errors = 0
    for rec in records:
        if rec['status'] == 'ERROR':
            errors += 1
        yield rec
    print(f'Total errors: {errors}')

# Pipeline — no list allocated
pipeline = compute_stats(
    parse_fields(
        filter_pattern(
            read_lines('server.log'),
            r'ERROR|WARN'
        )
    )
)

# Consume pipeline
for record in pipeline:
    pass

# Custom generator with state
def running_average():
    total = 0.0
    count = 0
    avg = None
    while True:
        value = yield avg  # receive via .send()
        if value is None:
            break
        total += value
        count += 1
        avg = total / count

avg = running_average()
next(avg)  # start
print(avg.send(10))  # 10.0
print(avg.send(20))  # 15.0
print(avg.send(30))  # 20.0

# === Function composition ===
def compose(*funcs):
    '''Compose functions right-to-left: compose(f, g)(x) = f(g(x))'''
    from functools import reduce
    def composed(x):
        return reduce(lambda acc, f: f(acc), reversed(funcs), x)
    return composed

# Pipeline as composition
def normalize(x): return x / 255.0
def resize(x): return x[::2, ::2]
def flatten(x): return x.reshape(-1)

preprocess = compose(flatten, resize, normalize)
# image -> normalize -> resize -> flatten

# === Trampoline for deep recursion ===
def trampoline(func):
    '''Converts recursive function into iterative trampoline'''
    def wrapped(*args):
        result = func(*args)
        while callable(result):
            result = result()
        return result
    return wrapped

@trampoline
def factorial(n, acc=1):
    if n == 0:
        return acc
    return lambda: factorial(n - 1, acc * n)

print(factorial(10000))  # No RecursionError

